  ('dietitian-moex-00323', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者不包括在社會支持（Social Support）最常使用的類型？', '["目標性支持", "情感性支持", "網絡性支持", "工具性支持"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00324', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '跨理論模式將行為改變分為五個階段，但其改變並非直線移動，許多個案在修正行為後，並不能成功維持而 退回前一個或更早的階段，甚至回到沉思前期（precontemplation），此行為模式稱為：', '["改變螺旋模式", "社會生態模式", "健康信念模式", "衛生教育診斷評價模式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00325', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某體重控制計畫對社區1,000名居民進行減重介入，計畫經費成本為20萬元，減重後可節省醫療資源支出50 萬元，則此計畫之「成本利益比」為何？', '["30萬／20萬", "20萬／50萬", "50萬／20萬", "50萬／70萬"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00326', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '社區營養計畫規劃者找到多項社區健康問題後，下列那一項標準不適合用來決定選擇問題的優先次序？', '["以疾病盛行率來評估社區健康問題的大小程度", "以媒體報導的關注程度來評估問題的嚴重性", "以計畫有效介入後可帶來社區健康問題減輕程度來評估計畫效益", "從政策面考量解決社區健康問題所需經費及相關資源是否許可"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00327', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於社區營養計畫的目標訂定，下列敘述何者正確？', '["直接目標（objective）可訂為「促進社區居民的健康和提升生活品質」", "工作達成目標（targets）可訂為「甲鄉60%糖尿病病人經由營養衛教，在一年內糖化血色素＜7%」", "最高目標（goal）通常比較確定，而且可以測量", "社區營養計畫重視結果，通常沒有訂定過程目標（process objective）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00328', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '以SWOT分析法進行「校園周邊健康飲食」可行策略的規劃。若分析學校內的學生營養知識及個人購買力，此 項分析屬於何者？', '["SW", "OT", "SO", "WT"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00329', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '執行社區營養計畫時所需考慮的細節或要件，可以「5W1H」來代表。其中，計畫目標之執行內容屬於下列何 者？', '["how", "what", "when", "why"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00330', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依民國82～85年、94～97年及102～105年三次全國營養調查結果發現，有關19歲以上國人之高血脂盛行率 （高膽固醇、低HDL-C、高LDL-C、高三酸甘油酯）變化之敘述，下列何者正確？', '["男性皆以高膽固醇盛行率最高", "女性皆以低HDL-C盛行率最高", "兩性高LDL-C盛行率有逐年降低之趨勢", "女性高三酸甘油酯盛行率皆高於男性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00331', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依82～85年、94～97年及102～105年三次全國營養調查分析，有關19歲以上國人高尿酸盛行率變化趨勢，下 列敘述何者正確？', '["兩性高尿酸盛行率逐年增高，且男性盛行率高於女性", "兩性高尿酸盛行率逐年減低，且男性盛行率高於女性", "高尿酸盛行率逐年增高，且女性盛行率高於男性", "高尿酸盛行率逐年減低，且女性盛行率高於男性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00332', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據民國102～105年國民營養健康狀況變遷調查結果，有關鈉攝取狀況之敘述，下列何者正確？', '["國民飲食指標建議，每日鈉總攝取量不宜超過2,000毫克", "國人2個月至6歲的嬰幼兒其鈉攝取量為所有年齡層中最高", "7歲以上的男女性族群其鈉攝取量換算均高於6公克鹽", "19至44歲女性鈉攝取量相當於10公克鹽"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
